class FiniteE8KAlgebra(ConeKAlgebra):
    """E_8 K-algebra with all data inlined."""

    _R = TrivialZPlusRing()

    def __init__(self):
        self._cone_data = _ExportedE8ConeData()

    def coefficient_ring(self):
        return self._R

    def identity(self):
        return ()

    def cone_data(self):
        return self._cone_data

    def rho(self, label):
        return tuple(sorted(
            (E8_RHO_PERM.get(i, i), p) for (i, p) in label
        ))

    def rho_inverse(self, label):
        rho_inv = {v: k for k, v in E8_RHO_PERM.items()}
        return tuple(sorted(
            (rho_inv.get(i, i), p) for (i, p) in label
        ))

    def _trace_residual(self, seed_label, K):
        from elem_traces import trace_residual
        return trace_residual('e8', self, seed_label, K)

_RHO_INV = {v: k for k, v in E8_RHO_PERM.items()}

def _rho_pow(idx, k):
    perm = E8_RHO_PERM if k >= 0 else _RHO_INV
    for _ in range(abs(k)):
        idx = perm[idx]
    return idx

def _rho_pow_word(word, k):
    return tuple(_rho_pow(i, k) for i in word)

class _ExportedE8ConeData(FiniteConeData):
    def mult_gens(self):
        return tuple(range(len(E8_MULT_GENS_LATTICE)))

    def cones(self):
        return tuple(frozenset(c) for c in E8_CONES)

    def q_commute(self, g, h):
        return g == h or (g, h) in E8_COCYCLE_TABLE

    def cocycle(self, g, h):
        if g == h: return 0
        return E8_COCYCLE_TABLE[(g, h)]

    def cross_product(self, g, h):
        i_rep, k = E8_RHO_ORBIT_REP_OF[g]
        h_rot = _rho_pow(h, -k)
        terms = E8_CROSS_TABLE_REDUCED.get((i_rep, h_rot), [])
        out = []
        for c, w in terms:
            if isinstance(c, dict):
                c = LaurentPoly(c)
            out.append((c, _rho_pow_word(w, k)))
        return tuple(out)

    def to_cone_label(self, native_label):
        gens = frozenset(i for i, p in native_label if p != 0)
        powers = {i: p for i, p in native_label if p != 0}
        return (gens, powers)

    def from_cone_label(self, gens, powers):
        return tuple(sorted((i, powers[i]) for i in gens))

    def cycle_period_bound(self):
        return len(E8_MULT_GENS_LATTICE)

